139	    success = opencc_->ConvertWord(original->text(), &forms);
140	    if (success) {
141	      for (size_t i = 0; i < forms.size(); ++i) {
142	        if (forms[i] == original->text()) {
143	          result->push_back(original);
144	        } else {
145	          PushBack(original, result, forms[i]);
