37	bool Opencc::ConvertWord(const string& text, vector<string>* forms) {
38	  Initialize();
39	  if (converter_ == nullptr) {
40	    return false;
41	  }
42	  const list<opencc::ConversionPtr> conversions =
43	      converter_->GetConversionChain()->GetConversions();
44	  vector<string> original_words{text};
45	  bool matched = false;
46	  for (auto conversion : conversions) {
47	    opencc::DictPtr dict = conversion->GetDict();
48	    if (dict == nullptr) {
49	      return false;
50	    }
51	    set<string> word_set;
52	    vector<string> converted_words;
53	    for (const auto& original_word : original_words) {
54	      opencc::Optional<const opencc::DictEntry*> item =
55	          dict->Match(original_word);
56	      if (item.IsNull()) {
57	        // There is no exact match, but still need to convert partially
58	        // matched in a chain conversion. Here apply default (max. seg.)
59	        // match to get the most probable conversion result
60	        std::ostringstream buffer;
61	        for (const char* wstr = original_word.c_str(); *wstr != '\0';) {
62	          opencc::Optional<const opencc::DictEntry*> matched =
63	              dict->MatchPrefix(wstr);
64	          size_t matched_length;
65	          if (matched.IsNull()) {
66	            matched_length = opencc::UTF8Util::NextCharLength(wstr);
67	            buffer << opencc::UTF8Util::FromSubstr(wstr, matched_length);
68	          } else {
69	            matched_length = matched.Get()->KeyLength();
70	            buffer << matched.Get()->GetDefault();
71	          }
72	          wstr += matched_length;
73	        }
74	        const string& converted_word = buffer.str();
75	        // Even if current dictionary doesn't convert the word
76	        // (converted_word == original_word), we still need to keep it for
77	        // subsequent dicts in the chain. e.g. s2t.json expands 里 to 里 and
78	        // 裏, then t2tw.json passes 里 as-is and converts 裏 to 裡.
79	        if (word_set.insert(converted_word).second) {
80	          converted_words.push_back(converted_word);
81	        }
82	        continue;
83	      }
84	      matched = true;
85	      const opencc::DictEntry* entry = item.Get();
86	      for (const auto& converted_word : entry->Values()) {
87	        if (word_set.insert(converted_word).second) {
88	          converted_words.push_back(converted_word);
89	        }
90	      }
91	    }
92	    original_words.swap(converted_words);
93	  }
94	  if (!matched) {
95	    // No dictionary contains the word
96	    return false;
97	  }
98	  *forms = std::move(original_words);
99	  return forms->size() > 0;
100	}
