102	bool Opencc::RandomConvertText(const string& text, string* simplified) {
103	  Initialize();
104	  if (dict_ == nullptr)
105	    return false;
106	  const list<opencc::ConversionPtr> conversions =
107	      converter_->GetConversionChain()->GetConversions();
108	  const char* phrase = text.c_str();
109	  for (auto conversion : conversions) {
110	    opencc::DictPtr dict = conversion->GetDict();
111	    if (dict == nullptr) {
112	      return false;
113	    }
114	    std::ostringstream buffer;
115	    for (const char* pstr = phrase; *pstr != '\0';) {
116	      opencc::Optional<const opencc::DictEntry*> matched =
117	          dict->MatchPrefix(pstr);
118	      size_t matched_length;
119	      if (matched.IsNull()) {
120	        matched_length = opencc::UTF8Util::NextCharLength(pstr);
121	        buffer << opencc::UTF8Util::FromSubstr(pstr, matched_length);
122	      } else {
123	        matched_length = matched.Get()->KeyLength();
124	        size_t i = rand() % (matched.Get()->NumValues());
125	        buffer << matched.Get()->Values().at(i);
126	      }
127	      pstr += matched_length;
128	    }
129	    *simplified = buffer.str();
130	    phrase = simplified->c_str();
131	  }
132	  return *simplified != text;
133	}
