9	
10	#include <rime/common.h>
11	
12	namespace rime {
13	
14	class Candidate {
15	 public:
16	  Candidate() = default;
17	  Candidate(const string& type, size_t start, size_t end, double quality = 0.)
18	      : type_(type), start_(start), end_(end), quality_(quality) {}
19	  virtual ~Candidate() = default;
20	
21	  static an<Candidate> GetGenuineCandidate(const an<Candidate>& cand);
22	  static vector<of<Candidate>> GetGenuineCandidates(const an<Candidate>& cand);
23	  int compare(const Candidate& other);
24	
25	  // recognized by translators in learning phase
26	  const string& type() const { return type_; }
27	  // [start, end) mark a range in the input that the candidate corresponds to
28	  size_t start() const { return start_; }
29	  size_t end() const { return end_; }
30	  double quality() const { return quality_; }
31	
32	  // candidate text to commit
33	  virtual const string& text() const = 0;
34	  // (optional)
35	  virtual string comment() const { return string(); }
36	  // text shown in the preedit area, replacing input string (optional)
37	  virtual string preedit() const { return string(); }
38	
39	  void set_type(const string& type) { type_ = type; }
40	  void set_start(size_t start) { start_ = start; }
41	  void set_end(size_t end) { end_ = end; }
42	  void set_quality(double quality) { quality_ = quality; }
43	
44	 private:
45	  string type_;
46	  size_t start_ = 0;
47	  size_t end_ = 0;
48	  double quality_ = 0.;
49	};
50	
51	using CandidateQueue = list<of<Candidate>>;
52	using CandidateList = vector<of<Candidate>>;
53	
54	// useful implementations
55	
56	class SimpleCandidate : public Candidate {
57	 public:
58	  SimpleCandidate() = default;
59	  SimpleCandidate(const string& type,
60	                  size_t start,
61	                  size_t end,
62	                  const string& text,
63	                  const string& comment = string(),
64	                  const string& preedit = string())
65	      : Candidate(type, start, end),
66	        text_(text),
67	        comment_(comment),
68	        preedit_(preedit) {}
69	
70	  const string& text() const { return text_; }
71	  string comment() const { return comment_; }
72	  string preedit() const { return preedit_; }
73	
74	  void set_text(const string& text) { text_ = text; }
75	  void set_comment(const string& comment) { comment_ = comment; }
76	  void set_preedit(const string& preedit) { preedit_ = preedit; }
77	
78	 protected:
79	  string text_;
80	  string comment_;
81	  string preedit_;
82	};
83	
84	class ShadowCandidate : public Candidate {
85	 public:
86	  ShadowCandidate(const an<Candidate>& item,
87	                  const string& type,
88	                  const string& text = string(),
89	                  const string& comment = string(),
90	                  const bool inherit_comment = true)
91	      : Candidate(type, item->start(), item->end(), item->quality()),
92	        text_(text),
93	        comment_(comment),
94	        item_(item),
95	        inherit_comment_(inherit_comment) {}
96	
97	  const string& text() const { return text_.empty() ? item_->text() : text_; }
98	  string comment() const {
99	    return inherit_comment_ && comment_.empty() ? item_->comment() : comment_;
100	  }
101	  string preedit() const { return item_->preedit(); }
102	
103	  const an<Candidate>& item() const { return item_; }
104	
105	 protected:
106	  string text_;
107	  string comment_;
108	  an<Candidate> item_;
109	  bool inherit_comment_;
110	};
111	
112	class UniquifiedCandidate : public Candidate {
113	 public:
114	  UniquifiedCandidate(const an<Candidate>& item,
115	                      const string& type,
116	                      const string& text = string(),
117	                      const string& comment = string())
118	      : Candidate(type, item->start(), item->end(), item->quality()),
119	        text_(text),
