10	namespace rime {
11	
12	int Translation::Compare(an<Translation> other,
13	                         const CandidateList& candidates) {
14	  if (!other || other->exhausted())
15	    return -1;
16	  if (exhausted())
17	    return 1;
18	  auto ours = Peek();
19	  auto theirs = other->Peek();
20	  if (!ours || !theirs)
21	    return 1;
22	  return ours->compare(*theirs);
23	}
24	
25	bool UniqueTranslation::Next() {
26	  if (exhausted())
27	    return false;
28	  set_exhausted(true);
29	  return true;
30	}
31	
32	an<Candidate> UniqueTranslation::Peek() {
33	  if (exhausted())
34	    return nullptr;
35	  return candidate_;
36	}
37	
38	FifoTranslation::FifoTranslation() {
39	  set_exhausted(true);
40	}
41	
42	bool FifoTranslation::Next() {
43	  if (exhausted())
44	    return false;
45	  if (++cursor_ >= candies_.size())
46	    set_exhausted(true);
47	  return true;
48	}
49	
50	an<Candidate> FifoTranslation::Peek() {
51	  if (exhausted())
52	    return nullptr;
53	  return candies_[cursor_];
54	}
55	
56	void FifoTranslation::Append(an<Candidate> candy) {
57	  candies_.push_back(candy);
58	  set_exhausted(false);
59	}
60	
61	UnionTranslation::UnionTranslation() {
62	  set_exhausted(true);
63	}
64	
65	bool UnionTranslation::Next() {
66	  if (exhausted())
67	    return false;
68	  translations_.front()->Next();
69	  if (translations_.front()->exhausted()) {
70	    translations_.pop_front();
71	    if (translations_.empty()) {
72	      set_exhausted(true);
73	    }
74	  }
75	  return true;
76	}
77	
78	an<Candidate> UnionTranslation::Peek() {
79	  if (exhausted())
80	    return nullptr;
81	  return translations_.front()->Peek();
82	}
83	
84	UnionTranslation& UnionTranslation::operator+=(an<Translation> t) {
85	  if (t && !t->exhausted()) {
86	    translations_.push_back(t);
87	    set_exhausted(false);
88	  }
89	  return *this;
90	}
91	
92	an<UnionTranslation> operator+(an<Translation> x, an<Translation> y) {
93	  auto z = New<UnionTranslation>();
94	  *z += x;
95	  *z += y;
96	  return z->exhausted() ? nullptr : z;
97	}
98	
99	// MergedTranslation
100	
101	MergedTranslation::MergedTranslation(const CandidateList& candidates)
102	    : previous_candidates_(candidates) {
103	  set_exhausted(true);
104	}
105	
106	bool MergedTranslation::Next() {
107	  if (exhausted()) {
108	    return false;
109	  }
110	  translations_[elected_]->Next();
111	  if (translations_[elected_]->exhausted()) {
112	    DLOG(INFO) << "translation #" << elected_ << " has been exhausted.";
113	    translations_.erase(translations_.begin() + elected_);
114	  }
115	  Elect();
116	  return !exhausted();
117	}
118	
119	an<Candidate> MergedTranslation::Peek() {
120	  if (exhausted()) {
121	    return nullptr;
122	  }
123	  return translations_[elected_]->Peek();
124	}
125	
126	void MergedTranslation::Elect() {
127	  if (translations_.empty()) {
128	    set_exhausted(true);
129	    return;
130	  }
131	  size_t k = 0;
132	  for (; k < translations_.size(); ++k) {
133	    const auto& current = translations_[k];
134	    const auto& next =
135	        k + 1 < translations_.size() ? translations_[k + 1] : nullptr;
136	    if (current->Compare(next, previous_candidates_) <= 0) {
137	      if (current->exhausted()) {
138	        translations_.erase(translations_.begin() + k);
139	        k = 0;
140	        continue;
141	      }
142	      break;
143	    }
144	  }
145	  elected_ = k;
146	  if (k >= translations_.size()) {
147	    DLOG(WARNING) << "failed to elect a winner translation.";
148	    set_exhausted(true);
149	  } else {
150	    set_exhausted(false);
151	  }
152	}
153	
154	MergedTranslation& MergedTranslation::operator+=(an<Translation> t) {
155	  if (t && !t->exhausted()) {
156	    translations_.push_back(t);
157	    Elect();
158	  }
159	  return *this;
160	}
161	
162	// CacheTranslation
163	
164	CacheTranslation::CacheTranslation(an<Translation> translation)
165	    : translation_(translation) {
166	  set_exhausted(!translation_ || translation_->exhausted());
167	}
168	
169	bool CacheTranslation::Next() {
170	  if (exhausted())
171	    return false;
172	  cache_.reset();
173	  translation_->Next();
174	  if (translation_->exhausted()) {
175	    set_exhausted(true);
176	  }
177	  return true;
178	}
179	
180	an<Candidate> CacheTranslation::Peek() {
181	  if (exhausted())
182	    return nullptr;
183	  if (!cache_) {
184	    cache_ = translation_->Peek();
185	  }
186	  return cache_;
187	}
188	
189	// DistinctTranslation
190	
191	DistinctTranslation::DistinctTranslation(an<Translation> translation)
192	    : CacheTranslation(translation) {}
193	
194	bool DistinctTranslation::Next() {
195	  if (exhausted())
196	    return false;
197	  candidate_set_.insert(Peek()->text());
198	  do {
199	    CacheTranslation::Next();
200	  } while (!exhausted() &&
201	           AlreadyHas(Peek()->text()));  // skip duplicate candidates
202	  return true;
203	}
204	
205	bool DistinctTranslation::AlreadyHas(const string& text) const {
206	  return candidate_set_.find(text) != candidate_set_.end();
207	}
208	
209	// PrefetchTranslation
210	
211	PrefetchTranslation::PrefetchTranslation(an<Translation> translation)
212	    : translation_(translation) {
213	  set_exhausted(!translation_ || translation_->exhausted());
214	}
215	
216	bool PrefetchTranslation::Next() {
217	  if (exhausted()) {
218	    return false;
219	  }
220	  if (!cache_.empty()) {
221	    cache_.pop_front();
222	  } else {
223	    translation_->Next();
224	  }
225	  if (cache_.empty() && translation_->exhausted()) {
226	    set_exhausted(true);
227	  }
228	  return true;
229	}
230	
231	an<Candidate> PrefetchTranslation::Peek() {
232	  if (exhausted()) {
233	    return nullptr;
234	  }
235	  if (!cache_.empty() || Replenish()) {
236	    return cache_.front();
237	  } else {
238	    return translation_->Peek();
239	  }
240	}
241	
242	}  // namespace rime
